// menu.js - كود واحد كامل
import { useState, useEffect, useCallback, useMemo, forwardRef, useImperativeHandle } from "react";

// دالة cn بسيطة
function cn(...classes) {
  return classes.filter(Boolean).join(" ");
}

// ========== مكون النص المتحرك TextRotate (مستوحى من الكود الأصلي) ==========
const TextRotate = forwardRef(({
  texts,
  rotationInterval = 2000,
  staggerDuration = 0.05,
  staggerFrom = "first",
  loop = true,
  auto = true,
  splitBy = "characters",
  onNext,
  mainClassName,
  splitLevelClassName,
  elementLevelClassName,
  ...props
}, ref) => {
  const [currentTextIndex, setCurrentTextIndex] = useState(0);
  const [visibleChars, setVisibleChars] = useState({});

  const splitIntoCharacters = (text) => {
    if (typeof Intl !== "undefined" && "Segmenter" in Intl) {
      const segmenter = new Intl.Segmenter("ar", { granularity: "grapheme" });
      return Array.from(segmenter.segment(text), ({ segment }) => segment);
    }
    return Array.from(text);
  };

  const elements = useMemo(() => {
    const currentText = texts[currentTextIndex];
    if (splitBy === "characters") {
      const text = currentText.split(" ");
      return text.map((word, i) => ({
        characters: splitIntoCharacters(word),
        needsSpace: i !== text.length - 1,
      }));
    }
    return splitBy === "words" ? currentText.split(" ") : currentText.split("\n");
  }, [texts, currentTextIndex, splitBy]);

  const getStaggerDelay = useCallback((index, totalChars) => {
    const total = totalChars;
    if (staggerFrom === "first") return index * staggerDuration;
    if (staggerFrom === "last") return (total - 1 - index) * staggerDuration;
    if (staggerFrom === "center") {
      const center = Math.floor(total / 2);
      return Math.abs(center - index) * staggerDuration;
    }
    if (staggerFrom === "random") {
      const randomIndex = Math.floor(Math.random() * total);
      return Math.abs(randomIndex - index) * staggerDuration;
    }
    return Math.abs(staggerFrom - index) * staggerDuration;
  }, [staggerFrom, staggerDuration]);

  const totalChars = useMemo(() => {
    if (splitBy === "characters") {
      return elements.reduce((sum, word) => sum + word.characters.length, 0);
    }
    return elements.length;
  }, [elements, splitBy]);

  // تأثير ظهور الحروف بالتتابع
  useEffect(() => {
    if (!auto) return;
    setVisibleChars({});
    
    const timeouts = [];
    for (let i = 0; i < totalChars; i++) {
      const delay = getStaggerDelay(i, totalChars) * 1000;
      const timeout = setTimeout(() => {
        setVisibleChars(prev => ({ ...prev, [i]: true }));
      }, delay);
      timeouts.push(timeout);
    }
    
    const resetTimeout = setTimeout(() => {
      setVisibleChars({});
    }, rotationInterval - 300);
    timeouts.push(resetTimeout);
    
    const nextTimeout = setTimeout(() => {
      const nextIndex = currentTextIndex === texts.length - 1
        ? (loop ? 0 : currentTextIndex)
        : currentTextIndex + 1;
      if (nextIndex !== currentTextIndex) {
        setCurrentTextIndex(nextIndex);
        onNext?.(nextIndex);
      }
    }, rotationInterval);
    timeouts.push(nextTimeout);
    
    return () => timeouts.forEach(t => clearTimeout(t));
  }, [currentTextIndex, texts.length, loop, auto, rotationInterval, totalChars, getStaggerDelay, onNext]);

  const next = useCallback(() => {
    const nextIndex = currentTextIndex === texts.length - 1 ? (loop ? 0 : currentTextIndex) : currentTextIndex + 1;
    if (nextIndex !== currentTextIndex) {
      setCurrentTextIndex(nextIndex);
      setVisibleChars({});
      onNext?.(nextIndex);
    }
  }, [currentTextIndex, texts.length, loop, onNext]);

  const previous = useCallback(() => {
    const prevIndex = currentTextIndex === 0 ? (loop ? texts.length - 1 : currentTextIndex) : currentTextIndex - 1;
    if (prevIndex !== currentTextIndex) {
      setCurrentTextIndex(prevIndex);
      setVisibleChars({});
      onNext?.(prevIndex);
    }
  }, [currentTextIndex, texts.length, loop, onNext]);

  useImperativeHandle(ref, () => ({ next, previous }));

  let charCounter = 0;
  
  return (
    <span className={cn("flex flex-wrap whitespace-pre-wrap", mainClassName)} {...props}>
      <span className="sr-only">{texts[currentTextIndex]}</span>
      <div className={cn("flex flex-wrap", splitBy === "lines" && "flex-col w-full")}>
        {(splitBy === "characters" ? elements : elements.map((el, i) => ({
          characters: [el],
          needsSpace: i !== elements.length - 1,
        }))).map((wordObj, wordIndex, array) => {
          const previousCharsCount = array.slice(0, wordIndex).reduce((sum, word) => sum + word.characters.length, 0);
          return (
            <span key={wordIndex} className={cn("inline-flex", splitLevelClassName)}>
              {wordObj.characters.map((char, charIndex) => {
                const globalCharIndex = previousCharsCount + charIndex;
                return (
                  <span key={charIndex}
                    style={{
                      display: "inline-block",
                      opacity: visibleChars[globalCharIndex] ? 1 : 0,
                      transform: visibleChars[globalCharIndex] ? "translateY(0)" : "translateY(30px)",
                      transition: `all 0.3s ease ${getStaggerDelay(globalCharIndex, totalChars)}s`,
                    }}
                    className={cn("inline-block", elementLevelClassName)}>
                    {char === " " ? "\u00A0" : char}
                  </span>
                );
              })}
              {wordObj.needsSpace && <span className="whitespace-pre"> </span>}
            </span>
          );
        })}
      </div>
    </span>
  );
});

// ========== كاردات المنتجات ==========
const cards = [
  { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", top: "15%", left: "3%", image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
  { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", top: "40%", left: "2%", image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
  { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", top: "20%", right: "3%", image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
  { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", top: "55%", right: "2%", image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
  { id: 5, name: "قهوة", icon: "☕", color: "#cd6133", top: "70%", left: "5%", image: "https://cdn-icons-png.flaticon.com/512/924/924514.png" },
  { id: 6, name: "عصائر", icon: "🍹", color: "#218c74", top: "80%", right: "5%", image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" }
];

// ========== المكون الرئيسي Menu ==========
export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const texts = ["مرحباً بكم", "أهلاً وسهلاً", "تفضلوا", "استمتعوا"];

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0f0c29, #302b63, #24243e)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.15) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* الكاردات */}
      {cards.map((card) => (
        <div key={card.id} style={{
          position: "fixed",
          top: card.top,
          left: card.left,
          right: card.right,
          transform: `translate(${mousePosition.x * (card.id % 2 === 0 ? 0.6 : -0.4)}px, ${mousePosition.y * (card.id % 2 === 0 ? -0.5 : 0.5)}px)`,
          transition: "transform 0.15s ease-out",
          zIndex: 10,
          cursor: "pointer"
        }}>
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}aa)`,
            width: "110px",
            padding: "18px 12px",
            borderRadius: "25px",
            textAlign: "center",
            boxShadow: "0 15px 35px rgba(0,0,0,0.3)",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255,255,255,0.25)",
            transition: "all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = "scale(1.15) rotate(5deg)";
            e.currentTarget.style.boxShadow = "0 25px 45px rgba(0,0,0,0.4)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 15px 35px rgba(0,0,0,0.3)";
          }}>
            <img src={card.image} alt={card.name} style={{ width: "50px", height: "50px", marginBottom: "8px", filter: "drop-shadow(2px 4px 6px black)" }} />
            <h3 style={{ color: "white", margin: "5px 0", fontSize: "1rem", fontWeight: "bold" }}>{card.name}</h3>
            <span style={{ fontSize: "1.8rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* النص المتحرك في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.2}px, ${mousePosition.y * 0.2}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.15s ease-out"
      }}>
        <div style={{
          background: "rgba(0,0,0,0.55)",
          backdropFilter: "blur(25px)",
          padding: "45px 70px",
          borderRadius: "50px",
          border: "2px solid rgba(34,197,94,0.6)",
          boxShadow: "0 0 60px rgba(34,197,94,0.25)"
        }}>
          <TextRotate
            texts={texts}
            rotationInterval={2500}
            auto={true}
            loop={true}
            splitBy="characters"
            staggerDuration={0.05}
            mainClassName="text-4xl font-bold"
            elementLevelClassName="inline-block"
            style={{
              fontSize: "3.5rem",
              fontWeight: "bold",
              background: "linear-gradient(135deg, #ffffff, #22c55e)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent"
            }}
          />
          <p style={{ color: "#ddd", marginTop: "15px", fontSize: "1.1rem" }}>✨ اكتشف قائمتنا ✨</p>
          <div style={{ width: "60px", height: "3px", background: "linear-gradient(90deg, #22c55e, transparent)", margin: "20px auto 0" }}></div>
        </div>
      </div>

      <div style={{ position: "fixed", bottom: "20px", left: "20px", color: "rgba(255,255,255,0.3)", fontSize: "12px", zIndex: 30 }}>
        ✨ حرك الماوس ✨
      </div>
    </div>
  );
}
